using Microsoft.VisualStudio.TestTools.UnitTesting;
using Warehouse;

namespace Warehouse.Tests;

[TestClass]
public sealed class InventoryTrackerTests
{
    private InventoryTracker _tracker = null!;

    [TestInitialize]
    public void Setup() => _tracker = new InventoryTracker();

    // ---------------------------------------------------------------
    //  GetStockLevel
    // ---------------------------------------------------------------

    [TestMethod]
    public void GetStockLevel_UnknownSku_ReturnsZero()
    {
        Assert.AreEqual(0, _tracker.GetStockLevel("SKU-UNKNOWN"));
    }

    [TestMethod]
    public void GetStockLevel_AfterAddStock_ReturnsCorrectLevel()
    {
        _tracker.AddStock("SKU-001", 25);
        Assert.AreEqual(25, _tracker.GetStockLevel("SKU-001"));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void GetStockLevel_InvalidSku_Throws(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(() => _tracker.GetStockLevel(sku!));
    }

    // ---------------------------------------------------------------
    //  AddStock
    // ---------------------------------------------------------------

    [TestMethod]
    public void AddStock_NewSku_SetsLevel()
    {
        _tracker.AddStock("SKU-A", 50);
        Assert.AreEqual(50, _tracker.GetStockLevel("SKU-A"));
    }

    [TestMethod]
    public void AddStock_ExistingSku_AccumulatesQuantity()
    {
        _tracker.AddStock("SKU-A", 20);
        _tracker.AddStock("SKU-A", 30);
        Assert.AreEqual(50, _tracker.GetStockLevel("SKU-A"));
    }

    [TestMethod]
    [DataRow(0)]
    [DataRow(-1)]
    [DataRow(-100)]
    public void AddStock_NonPositiveQuantity_Throws(int quantity)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _tracker.AddStock("SKU-A", quantity));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("  ")]
    public void AddStock_InvalidSku_Throws(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _tracker.AddStock(sku!, 10));
    }

    // ---------------------------------------------------------------
    //  RemoveStock
    // ---------------------------------------------------------------

    [TestMethod]
    public void RemoveStock_SufficientStock_ReducesLevel()
    {
        _tracker.AddStock("SKU-B", 40);
        _tracker.RemoveStock("SKU-B", 15);
        Assert.AreEqual(25, _tracker.GetStockLevel("SKU-B"));
    }

    [TestMethod]
    public void RemoveStock_ExactStock_SetsToZero()
    {
        _tracker.AddStock("SKU-B", 10);
        _tracker.RemoveStock("SKU-B", 10);
        Assert.AreEqual(0, _tracker.GetStockLevel("SKU-B"));
    }

    [TestMethod]
    public void RemoveStock_InsufficientStock_Throws()
    {
        _tracker.AddStock("SKU-B", 5);
        var ex = Assert.ThrowsException<InvalidOperationException>(
            () => _tracker.RemoveStock("SKU-B", 10));
        StringAssert.Contains(ex.Message, "Insufficient stock");
    }

    [TestMethod]
    public void RemoveStock_UnknownSku_Throws()
    {
        Assert.ThrowsException<InvalidOperationException>(
            () => _tracker.RemoveStock("SKU-MISSING", 1));
    }

    [TestMethod]
    [DataRow(0)]
    [DataRow(-5)]
    public void RemoveStock_NonPositiveQuantity_Throws(int quantity)
    {
        _tracker.AddStock("SKU-B", 20);
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _tracker.RemoveStock("SKU-B", quantity));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    public void RemoveStock_InvalidSku_Throws(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _tracker.RemoveStock(sku!, 1));
    }

    // ---------------------------------------------------------------
    //  NeedsReorder  (default threshold = 10)
    // ---------------------------------------------------------------

    [TestMethod]
    public void NeedsReorder_StockBelowDefault_ReturnsTrue()
    {
        _tracker.AddStock("SKU-C", 5);
        Assert.IsTrue(_tracker.NeedsReorder("SKU-C"));
    }

    [TestMethod]
    public void NeedsReorder_StockAtDefault_ReturnsTrue()
    {
        _tracker.AddStock("SKU-C", 10);
        Assert.IsTrue(_tracker.NeedsReorder("SKU-C"));
    }

    [TestMethod]
    public void NeedsReorder_StockAboveDefault_ReturnsFalse()
    {
        _tracker.AddStock("SKU-C", 11);
        Assert.IsFalse(_tracker.NeedsReorder("SKU-C"));
    }

    [TestMethod]
    public void NeedsReorder_ZeroStock_ReturnsTrue()
    {
        Assert.IsTrue(_tracker.NeedsReorder("SKU-NEW"));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    public void NeedsReorder_InvalidSku_Throws(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _tracker.NeedsReorder(sku!));
    }

    // ---------------------------------------------------------------
    //  SetReorderThreshold
    // ---------------------------------------------------------------

    [TestMethod]
    public void SetReorderThreshold_CustomValue_AffectsNeedsReorder()
    {
        _tracker.SetReorderThreshold("SKU-D", 50);
        _tracker.AddStock("SKU-D", 30);
        Assert.IsTrue(_tracker.NeedsReorder("SKU-D"));

        _tracker.AddStock("SKU-D", 25); // now 55
        Assert.IsFalse(_tracker.NeedsReorder("SKU-D"));
    }

    [TestMethod]
    public void SetReorderThreshold_Zero_OnlyReordersWhenEmpty()
    {
        _tracker.SetReorderThreshold("SKU-E", 0);
        _tracker.AddStock("SKU-E", 1);
        Assert.IsFalse(_tracker.NeedsReorder("SKU-E"));

        _tracker.RemoveStock("SKU-E", 1);
        Assert.IsTrue(_tracker.NeedsReorder("SKU-E"));
    }

    [TestMethod]
    public void SetReorderThreshold_NegativeValue_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _tracker.SetReorderThreshold("SKU-E", -1));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    public void SetReorderThreshold_InvalidSku_Throws(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _tracker.SetReorderThreshold(sku!, 5));
    }

    // ---------------------------------------------------------------
    //  TransferStock
    // ---------------------------------------------------------------

    [TestMethod]
    public void TransferStock_ValidTransfer_MovesStockBetweenWarehouses()
    {
        var destination = new InventoryTracker();
        _tracker.AddStock("SKU-F", 100);

        _tracker.TransferStock(destination, "SKU-F", 40);

        Assert.AreEqual(60, _tracker.GetStockLevel("SKU-F"));
        Assert.AreEqual(40, destination.GetStockLevel("SKU-F"));
    }

    [TestMethod]
    public void TransferStock_EntireStock_SourceBecomesZero()
    {
        var destination = new InventoryTracker();
        _tracker.AddStock("SKU-F", 20);

        _tracker.TransferStock(destination, "SKU-F", 20);

        Assert.AreEqual(0, _tracker.GetStockLevel("SKU-F"));
        Assert.AreEqual(20, destination.GetStockLevel("SKU-F"));
    }

    [TestMethod]
    public void TransferStock_DestinationAlreadyHasStock_Accumulates()
    {
        var destination = new InventoryTracker();
        destination.AddStock("SKU-F", 10);
        _tracker.AddStock("SKU-F", 30);

        _tracker.TransferStock(destination, "SKU-F", 15);

        Assert.AreEqual(15, _tracker.GetStockLevel("SKU-F"));
        Assert.AreEqual(25, destination.GetStockLevel("SKU-F"));
    }

    [TestMethod]
    public void TransferStock_InsufficientStock_Throws_AndNoSideEffects()
    {
        var destination = new InventoryTracker();
        _tracker.AddStock("SKU-G", 5);

        Assert.ThrowsException<InvalidOperationException>(
            () => _tracker.TransferStock(destination, "SKU-G", 10));

        // Neither warehouse should be modified
        Assert.AreEqual(5, _tracker.GetStockLevel("SKU-G"));
        Assert.AreEqual(0, destination.GetStockLevel("SKU-G"));
    }

    [TestMethod]
    public void TransferStock_NullDestination_Throws()
    {
        _tracker.AddStock("SKU-G", 10);
        Assert.ThrowsException<ArgumentNullException>(
            () => _tracker.TransferStock(null!, "SKU-G", 5));
    }

    [TestMethod]
    [DataRow(0)]
    [DataRow(-1)]
    public void TransferStock_NonPositiveQuantity_Throws(int quantity)
    {
        var destination = new InventoryTracker();
        _tracker.AddStock("SKU-G", 10);
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _tracker.TransferStock(destination, "SKU-G", quantity));
    }

    // ---------------------------------------------------------------
    //  Integration-style: multi-SKU scenarios
    // ---------------------------------------------------------------

    [TestMethod]
    public void MultipleSkus_IndependentTracking()
    {
        _tracker.AddStock("WIDGET", 100);
        _tracker.AddStock("GADGET", 200);
        _tracker.RemoveStock("WIDGET", 30);

        Assert.AreEqual(70, _tracker.GetStockLevel("WIDGET"));
        Assert.AreEqual(200, _tracker.GetStockLevel("GADGET"));
    }

    [TestMethod]
    public void ReorderAlert_TriggersAfterRemoval()
    {
        _tracker.SetReorderThreshold("SKU-H", 20);
        _tracker.AddStock("SKU-H", 50);
        Assert.IsFalse(_tracker.NeedsReorder("SKU-H"));

        _tracker.RemoveStock("SKU-H", 35); // now 15
        Assert.IsTrue(_tracker.NeedsReorder("SKU-H"));
    }

    [TestMethod]
    public void TransferTriggersReorderOnSource()
